#!/usr/bin/env bash
set -euo pipefail

# Freddy Fix It — "Estimate" rename + adjust-price-anytime-until-payout installer.
# (1) Renames every customer-facing "quote"/"quotes" to "estimate"/"estimates" across
#     the site + legal docs (route paths + DB identifiers untouched).
# (2) Lets contractors adjust a job's price at any live stage up until payout — including
#     after they mark it complete (pending client confirmation). Two-sided completion
#     (contractor marks done -> client confirms -> funds release) is preserved.
# DB + edge-function DEPLOYS are already LIVE (via Supabase MCP); this ships the FRONTEND
# plus committed copies of the changed edge-function source for version control.
# Resets to published origin/main first, so running THIS delivers everything.

TARGET="$HOME/Desktop/freddy-fixit"
if [ ! -d "$TARGET/.git" ]; then echo "❌ $TARGET is not a git repo"; exit 1; fi
cd "$TARGET"
echo "→ Syncing to the published version (discards any half-applied local state)"
git fetch origin --quiet || true
git reset --hard origin/main --quiet
echo "→ Writing files into $TARGET"

write_file() {  # write_file <destpath> ; base64 body on stdin
  local dest="$1"
  mkdir -p "$(dirname "$dest")"
  base64 --decode > "$dest"
}

echo "  • src/pages/Home.tsx"
write_file 'src/pages/Home.tsx' <<'B64_0'
